module top_module(
    input signed [7:0] a,
    input signed [7:0] b,
    input sel,
    input reset,
    input clk,
    output signed [15:0] out
);reg signed [15:0] product;
reg signed [15:0] sum;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
        product <= 0;
        sum <= 0;
    end else begin
        if (sel) begin
            sum <= a + b;
        end else begin
            product <= a * b;
        end
    end
end

assign out = sel ? sum : product;

endmodule
